#include "menu.h"

#include <ctype.h>
#include <limits.h>
#include <stdio.h>
#include <string.h>

/* ---- internal types ---------------------------------------------------- */

/** Classification of a single token within a command syntax string. */
typedef enum MenuTokenType {
    MENU_TOKEN_KEYWORD = 0,       /**< Literal keyword (e.g. DAQ, SET).    */
    MENU_TOKEN_REQUIRED_PARAM,    /**< Required parameter [NAME].          */
    MENU_TOKEN_OPTIONAL_PARAM     /**< Optional parameter {NAME}.          */
} MenuTokenType;

/** One parsed token from a syntax definition. */
typedef struct ParsedToken {
    MenuTokenType type;           /**< Token classification.               */
    char          text[32];       /**< Keyword text or parameter name.     */
} ParsedToken;

/** Pre-parsed metadata for one command used at dispatch time. */
typedef struct ParsedCommand {
    ParsedToken tokens[MENU_MAX_TOKENS]; /**< Parsed syntax tokens.        */
    int         token_count;             /**< Total tokens in syntax.       */
    int         min_tokens;              /**< Min input tokens for match.   */
    int         max_tokens;              /**< Max input tokens for match.   */
    int         valid;                   /**< 1 if syntax parsed cleanly.   */
} ParsedCommand;

